def init_checkers_board():
    board = [[' ' for _ in range(8)] for _ in range(8)]

    # Place red checkers
    for i in range(3):
        for j in range((i % 2) + 1, 8, 2):
            board[i][j] = 'r'

    # Place black checkers
    for i in range(5, 8):
        for j in range(((i - 4) % 2) + 1, 8, 2):
