    if not (0 <= start[0] < 8 and 0 <= start[1] < 8 and 0 <= end[0] < 8 and 0 <= end[1] < 8):
        return False

    piece = board[start[0]][start[1]]
    if not (piece == 'r' or piece == 'R') or (piece == 'b' and 'B' in [board[end[0]][end[1]] for end in get_possible_moves(board, start)]):
        return False

    if board[end[0]][end[1]] != ' ':
        return False

    # Handle capture
    if abs(start[0] - end[0]) == 2 and abs(start[1] - end[1]) == 2:
        mid_x, mid_y = (start[0] + end[0]) // 2, (start[1] + end[1]) // 2
        if board[mid_x][mid_y] != 'b' and board[mid_x][mid_y] != 'R':
            return False

    # Handle kinging
    if piece == 'r' and end[0] == 7:
        return True
    elif piece == 'b' and end[0] == 0:
        return True

    return True

